#[wasm_bindgen]
pub fn chain_to_abstract_lattice_edge_js(
    chain_points: JsValue,
    params: JsValue,
    region_debug: JsValue,
) -> Result<JsValue, JsValue> {
    let chain_points: Vec<Vec2> = serde_wasm_bindgen::from_value(chain_points)?;
    let params: ParkingParams = serde_wasm_bindgen::from_value(params)?;
    let region_debug: Option<RegionDebug> = serde_wasm_bindgen::from_value(region_debug)?;
    let result =
        resolve::chain_to_abstract_lattice_edge(&chain_points, &params, region_debug.as_ref());
    Ok(serde_wasm_bindgen::to_value(&result)?)
}

#[wasm_bindgen]
pub fn chain_extents_in_region_js(
    chain_points: JsValue,
    params: JsValue,
    region: JsValue,
) -> Result<JsValue, JsValue> {
    let chain_points: Vec<Vec2> = serde_wasm_bindgen::from_value(chain_points)?;
    let params: ParkingParams = serde_wasm_bindgen::from_value(params)?;
    let region: RegionInfo = serde_wasm_bindgen::from_value(region)?;
    let result = resolve::chain_extents_in_region(&chain_points, &params, &region);
    Ok(serde_wasm_bindgen::to_value(&result)?)
}

// ---------------------------------------------------------------------------
// Point-in-polygon primitive. Pure geometry; exposed so the UI can
// drop its hand-rolled copy.
// ---------------------------------------------------------------------------

#[wasm_bindgen]
pub fn point_in_polygon_js(px: f64, py: f64, poly: JsValue) -> Result<bool, JsValue> {
    let poly: Vec<Vec2> = serde_wasm_bindgen::from_value(poly)?;
    Ok(crate::geom::clip::point_in_polygon(
        &Vec2::new(px, py),
        &poly,
    ))
}

/// Distance from point `(px, py)` to the segment `(ax, ay) → (bx, by)`.
#[wasm_bindgen]
pub fn point_to_segment_dist_js(
    px: f64, py: f64, ax: f64, ay: f64, bx: f64, by: f64,
) -> f64 {
    point_to_segment_dist(Vec2::new(px, py), Vec2::new(ax, ay), Vec2::new(bx, by))
}

/// `resolve::hit_test_edge` — returns the deduplicated edge index
/// or `null` if no edge is within `world_radius`.
#[wasm_bindgen]
pub fn hit_test_edge_js(
    wx: f64,
    wy: f64,
    graph: JsValue,
    world_radius: f64,
) -> Result<JsValue, JsValue> {
    let graph: DriveAisleGraph = serde_wasm_bindgen::from_value(graph)?;
    let result = resolve::hit_test_edge(Vec2::new(wx, wy), &graph, world_radius);
    Ok(serde_wasm_bindgen::to_value(&result)?)
}

/// `resolve::find_collinear_chain` — deduplicated edge indices on the
/// same collinear run as `seed_idx`.
#[wasm_bindgen]
pub fn find_collinear_chain_js(
    graph: JsValue,
    seed_idx: usize,
) -> Result<Vec<usize>, JsValue> {
    let graph: DriveAisleGraph = serde_wasm_bindgen::from_value(graph)?;
    Ok(resolve::find_collinear_chain(&graph, seed_idx))
}

/// `resolve::resolve_grid_target` — from an edge selection (seed +
/// chain + mode) to a `Target::Grid`, or null if the selection doesn't
/// sit on grid-aligned lattice vertices.
#[wasm_bindgen]
pub fn resolve_grid_target_js(
    seed_index: usize,
    chain: Vec<usize>,
    is_chain_mode: bool,
    graph: JsValue,
    params: JsValue,
    region_debug: JsValue,
) -> Result<JsValue, JsValue> {
    let graph: DriveAisleGraph = serde_wasm_bindgen::from_value(graph)?;
    let params: ParkingParams = serde_wasm_bindgen::from_value(params)?;
    let region_debug: Option<RegionDebug> = serde_wasm_bindgen::from_value(region_debug)?;
    let result = match region_debug.as_ref() {
        Some(rd) => resolve::resolve_grid_target(seed_index, &chain, is_chain_mode, &graph, &params, rd),
        None => None,
    };
    Ok(serde_wasm_bindgen::to_value(&result)?)
}

/// `resolve::targets_equal` — structural equality over `Target`.
#[wasm_bindgen]
pub fn targets_equal_js(a: JsValue, b: JsValue) -> Result<bool, JsValue> {
    let a: Target = serde_wasm_bindgen::from_value(a)?;
    let b: Target = serde_wasm_bindgen::from_value(b)?;
    Ok(resolve::targets_equal(&a, &b))
}
